APP_NAME = "screenshot-service"
DEFAULT_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots/")
PUBLIC_BASE_URL = os.getenv("PUBLIC_BASE_URL", "")
CHROME_BINARY = os.getenv("CHROME_BINARY", "/usr/bin/google-chrome")
CHROMEDRIVER_PATH = os.getenv("CHROMEDRIVER_PATH", "/usr/bin/chromedriver")
SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMBNAIL_WIDTH = int(os.getenv("THUMBNAIL_WIDTH", "400"))
THUMBNAIL_HEIGHT = int(os.getenv("THUMBNAIL_HEIGHT", "225"))
PAGE_LOAD_TIMEOUT = int(os.getenv("PAGE_LOAD_TIMEOUT", "30"))
RENDER_WAIT_SECONDS = float(os.getenv("RENDER_WAIT_SECONDS", "2.5"))
MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))
ALLOWED_SCHEMES = {"http", "https"}
CACHE_CONTROL = os.getenv("CACHE_CONTROL", "public, max-age=31536000, immutable")
LOG_LEVEL = os.getenv("LOG_LEVEL", "INFO").upper()
MAX_IMAGE_BYTES = int(os.getenv("MAX_IMAGE_BYTES", str(5 * 1024 * 1024)))
DISABLE_PRIVATE_IPS = os.getenv("DISABLE_PRIVATE_IPS", "true").lower() == "true"

