_driver_lock = threading.Lock()


def now_iso():
    return datetime.now(timezone.utc).isoformat()


def normalize_prefix(prefix: str) -> str:
    if not prefix:
        return ""
    return prefix if prefix.endswith("/") else prefix + "/"


S3_PREFIX = normalize_prefix(S3_PREFIX)


def validate_url(url: str) -> str:
    if not url or not isinstance(url, str):
        raise ValueError("url is required")
    url = url.strip()
    if len(url) > MAX_URL_LENGTH:
        raise ValueError("url too long")
    parsed = urlparse(url)
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise ValueError("only http and https are allowed")
    if not parsed.netloc:
        raise ValueError("invalid url")
    host = parsed.hostname or ""
    if not re.match(r"^[A-Za-z0-9\.\-\_]+$", host):
        raise ValueError("invalid hostname")
    if DISABLE_PRIVATE_IPS and is_private_or_local_host(host):
        raise ValueError("private, local, and metadata addresses are not allowed")
    return url


def is_private_or_local_host(host: str) -> bool:
    import ipaddress
    import socket

    blocked_hosts = {
        "localhost",
        "127.0.0.1",
        "::1",
        "0.0.0.0",
        "169.254.169.254",
    }
    if host.lower() in blocked_hosts:
        return True
    try:
        ip = ipaddress.ip_address(host)
        return (
            ip.is_private
            or ip.is_loopback
            or ip.is_link_local
            or ip.is_multicast
            or ip.is_reserved
            or ip.is_unspecified
        )
    except ValueError:
        pass
    try:
        infos = socket.getaddrinfo(host, None)
        for info in infos:
            addr = info[4][0]
            try:
                ip = ipaddress.ip_address(addr)
                if (
                    ip.is_private
                    or ip.is_loopback
                    or ip.is_link_local
                    or ip.is_multicast
                    or ip.is_reserved
                    or ip.is_unspecified
                ):
                    return True
            except ValueError:
                continue
    except Exception:
        return True
    return False


def url_hash(url: str) -> str:
    return hashlib.sha256(url.encode("utf-8")).hexdigest()


def build_s3_key(url: str, ext: str = "jpg") -> str:
    h = url_hash(url)
    return f"{S3_PREFIX}{h[:2]}/{h[2:4]}/{h}.{ext}"


def build_metadata(url: str) -> dict:
    return {
        "source_url": url[:1024],
        "generated_at": now_iso(),
        "service": APP_NAME,
    }


def get_public_url(key: str) -> str:
    if PUBLIC_BASE_URL:
        return f"{PUBLIC_BASE_URL.rstrip('/')}/{key}"
    region = DEFAULT_REGION
    return f"https://{S3_BUCKET}.s3.{region}.amazonaws.com/{key}"


def s3_head_object(bucket: str, key: str):
    try:
        return s3.head_object(Bucket=bucket, Key=key)
    except botocore.exceptions.ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("404", "NoSuchKey", "NotFound"):
            return None
        raise


def create_driver():
    if webdriver is None:
        raise RuntimeError("selenium is not installed")
    options = ChromeOptions()
    options.binary_location = CHROME_BINARY
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--window-size=%d,%d" % (SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
    options.add_argument("--disable-software-rasterizer")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--ignore-certificate-errors")
    prefs = {
        "profile.managed_default_content_settings.images": 1,
        "disk-cache-size": 0,
    }
    options.add_experimental_option("prefs", prefs)
    service = ChromeService(executable_path=CHROMEDRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
    return driver


def capture_screenshot(url: str) -> bytes:
    with _driver_lock:
        driver = create_driver()
        try:
            driver.get(url)
            time.sleep(RENDER_WAIT_SECONDS)
            png = driver.get_screenshot_as_png()
            return png
        finally:
            try:
                driver.quit()
            except Exception:
                pass


def make_thumbnail(image_bytes: bytes) -> bytes:
    with Image.open(io.BytesIO(image_bytes)) as img:
        img = img.convert("RGB")
        img.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT))
        out = io.BytesIO()
        img.save(out, format="JPEG", quality=85, optimize=True)
        data = out.getvalue()
        if len(data) > MAX_IMAGE_BYTES:
            raise ValueError("thumbnail too large")
        return data


def upload_to_s3(bucket: str, key: str, body: bytes, metadata: dict):
    extra = {
        "ContentType": "image/jpeg",
        "CacheControl": CACHE_CONTROL,
        "Metadata": metadata,
    }
    s3.put_object(Bucket=bucket, Key=key, Body=body, **extra)


def generate_thumbnail_for_url(url: str, force: bool = False) -> dict:
    if not S3_BUCKET:
        raise RuntimeError("S3_BUCKET is not configured")
    url = validate_url(url)
    key = build_s3_key(url, "jpg")
    existing = s3_head_object(S3_BUCKET, key)
    if existing and not force:
        return {
            "status": "cached",
            "url": url,
            "s3_bucket": S3_BUCKET,
            "s3_key": key,
            "thumbnail_url": get_public_url(key),
            "etag": existing.get("ETag", "").strip('"'),
            "generated_at": existing.get("LastModified").isoformat() if existing.get("LastModified") else None,
        }

    screenshot_png = capture_screenshot(url)
    thumbnail_jpg = make_thumbnail(screenshot_png)
    metadata = build_metadata(url)
    upload_to_s3(S3_BUCKET, key, thumbnail_jpg, metadata)

    return {
        "status": "generated",
        "url": url,
        "s3_bucket": S3_BUCKET,
        "s3_key": key,
        "thumbnail_url": get_public_url(key),
        "size_bytes": len(thumbnail_jpg),
        "generated_at": now_iso(),
    }


