@app.post("/screenshot")
def screenshot():
    try:
        payload = request.get_json(silent=True) or {}
        url = payload.get("url") or request.args.get("url")
        force = str(payload.get("force", request.args.get("force", "false"))).lower() == "true"
        result = generate_thumbnail_for_url(url, force=force)
        return jsonify(result), 200
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.exception("screenshot generation failed")
        return jsonify({"error": "internal server error", "detail": str(e)}), 500


